    /// Compute CRC-16 parity for Binex, NVS, and other NMEA-style data.
    /// Implements CRC-16/CCITT-FALSE (Polynomial 0x1021, Initial 0x0000).
    public static func calcCRC16<S: Sequence>(_ data: S) -> UInt16 where S.Element == UInt8 {
        var crc: UInt16 = 0
        for byte in data {
            crc = (crc << 8) ^ tbl_CRC16[Int(((crc >> 8) ^ UInt16(byte)) & 0xFF)]
        }
        return crc
    }
    
