    /// Compute generic bit-wise CRC-24.
    public static func calcCRC24<S: Sequence>(_ polynomial: UInt32, data: S) -> UInt32 where S.Element == UInt8 {
        var crc: UInt32 = 0
        for byte in data {
            crc ^= UInt32(byte) << 16
            for _ in 0..<8 {
                crc <<= 1
                if (crc & 0x1000000) != 0 {
                    crc ^= polynomial
                }
            }
        }
        return crc & 0xFFFFFF
    }
    
    /// Compute optimized CRC-24Q parity for SBAS and RTCM3.
    public static func calcCRC24Q<S: Sequence>(_ data: S) -> UInt32 where S.Element == UInt8 {
        var crc: UInt32 = 0
        for byte in data {
            crc = ((crc << 8) & 0xFFFFFF) ^ tbl_CRC24Q[Int((crc >> 16) ^ UInt32(byte))]
        }
        return crc
    }
    
