    /// Compute CRC-32 parity for NovAtel and other binary data streams.
    ///
    /// Implements the standard CRC-32 (Polynomial 0xEDB88320, Initial 0x00000000).
    ///
    /// - Parameter data: A sequence of bytes to process.
    /// - Returns: The calculated 32-bit CRC value.
    public static func calcCRC32<S: Sequence>(_ data: S) -> UInt32 where S.Element == UInt8 {
        var crc: UInt32 = 0
        for byte in data {
            crc = tbl_CRC32[Int((crc ^ UInt32(byte)) & 0xFF)] ^ (crc >> 8)
        }
        return crc
    }
    
    /// Calculate a single CRC-32 table entry on-the-fly.
    ///
    /// - Parameter i: The table index (0-255).
    /// - Returns: The CRC table entry.
    public static func calcCRC32Val(_ i: UInt32) -> UInt32 {
        var crc = i
        for _ in 0..<8 {
            if (crc & 1) != 0 {
                crc = (crc >> 1) ^ POLYCRC32
            } else {
                crc >>= 1
            }
        }
        return crc
    }
